mutation M130_signMoneyInOut($data: MoneyInOutInput!, $training: Boolean! = false) {
  signMoneyInOut(data: $data, isTraining: $training) {
    posId
    posFiscalTicketNo
    posDateTime
    terminalId
    deviceId
    fdmSwVersion
    eventOperation
    digitalSignature
    bufferCapacityUsed
    fdmRef {
      fdmId
      fdmDateTime
      eventLabel
      eventCounter
      totalCounter
    }
    warnings {
      category
      code
      message
      data {
        name
        value
      }
      showPos
    }
    informations {
      category
      code
      message
      data {
        name
        value
      }
      showPos
    }
  }
}
